var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"헉, 헉…! 어서 지원 보내 달라고 회사에 연락해!","JPN":"はあ、はっ……！　早く支援を送ってくれと会社に連絡しろ！","ENG":"*Huff... Huff...* Call the company for backup, now!","TWN":"呼，呼…！快通知公司派支援來！"},"stage":{"bg":"CLOSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장, 침식체들이 어디서 이렇게 많이 나타난 거야?","JPN":"くそ、どこからこんな大量の侵食体が現れやがったんだ？","ENG":"Dammit! Where are all these C.O.s coming from?","TWN":"該死，從哪冒出來這麼多的侵蝕體？"},"stage":{"bg":"CLOSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"대체 얼마나 죽어 나간 거야…. 그 괴물은 또 뭐냐고!","JPN":"いったい何人死んだんだ……あのバケモンはまた何なんだよ！","ENG":"How many of them have we killed...? And what the hell is that monster?!","TWN":"到底死了多少人…那個怪物又是什麼鬼！"},"stage":{"bg":"CLOSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아저씨, 여기라면 안전할 거예요. 우리 잠깐만 쉬어요.","JPN":"おじさん、ここなら安全です。ちょっとだけ休みましょう？","ENG":"Mister, I think we're safe here. Let's rest here a little.","TWN":"大叔，這裡應該很安全，我們休息一下吧。"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"그, 그래.","JPN":"あ、ああ。","ENG":"S-sure.","TWN":"嗯，好。"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"덕분에 살았어…. 네 무기, 보기보다 위력이 대단하더라.","JPN":"おかげで助かった……お前の武器、見た目よりすごい威力だな。","ENG":"I'm still alive thanks to you... Your weapon is a lot stronger than it looks.","TWN":"幸好有你，我才能保住小命… 你的武器實際上比看起來還威呢。"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗. 네. 천사님도 이게 절 지켜 줄 거라고 하셨거든요.","JPN":"あっ、はい。天使様もこの武器が私を守ってくれるっておっしゃってました。","ENG":"Oh, yes. The angel told me that it would protect me.","TWN":"是啊，天使也說這個可以保護我。"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여행을 다닐 때는 위험한 일들이 많이 일어난다면서요.","JPN":"旅の途中には危ないことがいっぱい起きるからって。","ENG":"She said that danger lurks in every corner when you are traveling.","TWN":"旅行的時候經常會發生許多危險的事呢。"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"천사님…?","JPN":"天使様……？","ENG":"Angel...?","TWN":"天使…？"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"어~이!","JPN":"おーい！","ENG":"Hey!","TWN":"有～人～嗎！"},"stage":{"bg":"CLOSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어? 저 목소리는…?","JPN":"あれ？　あの声は……？","ENG":"Huh? Isn't that voice...?","TWN":"嗯？這個聲音是…？"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"어이! 다들 어디 있는 거야!","JPN":"おい！　みんなどこだ！","ENG":"Hey! Where are ya guys?","TWN":"喂！大家在哪！"},"stage":{"bg":"CLOSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"침식체들은 이미 가 버렸어! 이제 숨어 있지 않아도 돼!","JPN":"侵食体どもはもういなくなったぞ！　隠れなくても大丈夫だ！","ENG":"The C.O.s are gone! You can come out now!","TWN":"侵蝕體都離開了！不用再躲了！"},"stage":{"bg":"CLOSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"저… 저 친구? 살아 있었나?","JPN":"あ……あいつ？　生きてたのか？","ENG":"H-how is it that... he's still alive?","TWN":"是…我朋友？他還活著嗎？"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아저씨, 안 돼요! 아까 피를 흘리면서 쓰러지는 모습 보셨잖아요!","JPN":"おじさん、ダメです！　さっき血を流しながら倒れる姿を見たじゃないですか！","ENG":"Mister, No! You saw him fall down bleeding.","TWN":"大叔，不可以！你剛不是也有看到他流血倒下嗎！"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"다, 닥쳐 봐! 내 친구 목소리야!","JPN":"だ、黙れ！　俺のダチの声に違いねえ！","ENG":"S-shut up! That's my friend's voice! I'm certain of it!","TWN":"住，住口！那是我朋友的聲音！"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_B","text":{"KOREA":"다들 집에 안 갈 거야? 어서 나와!","JPN":"みんな、家に帰らねえのか？　早く出て来いよ！","ENG":"Aren't y'all gonna go home? Let's go!","TWN":"我們回家吧？你們快出來！"},"stage":{"bg":"CLOSE","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"다친 사람 목소리치고는 너무 멀쩡하잖아요! 이상해요!","JPN":"怪我人の声にしてはあまりにも元気すぎます！　おかしいですよ！","ENG":"He sounds too well for someone who was injured! That's weird!","TWN":"一個受傷的人聲音會那麼有力嗎！不對勁！"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PMC_NPC_COMPLETE_A","text":{"KOREA":"빌어먹을…! 확인만 하고 오면 되잖아! 확인만!","JPN":"くそ……！　確認するくらいいいだろ！　確認だけ！","ENG":"Dammit...! At least let me check if it's him or not!","TWN":"該死…！我去看一下總可以吧！確認一下就好！"},"stage":{"bg":"CLOSE","slots":{"L":{"char_id":"PMC_NPC_COMPLETE_A","face":"UNIT_IDLE"},"C":null,"R":null}}}]`);export{e as default};